INSERT INTO `glpi_itilfollowups` VALUES
(2,'Ticket',1,'2025-10-16 13:48:52',2,0,'&#60;p&#62;&#60;strong&#62;Bonjour Raphaël, Bonjour Steeve,&#60;/strong&#62;&#60;/p&#62;\r\n&#60;p&#62;Suite à vos demandes respectives – l\'une pour la suppression de l\'application Zefyr, l\'autre pour un rétablissement d\'accès urgent – nous avons bien pris en compte la situation.&#60;/p&#62;\r\n&#60;p&#62;Nous comprenons qu\'il s\'agit d\'un sujet important pour le service comptabilité. Avant toute action technique de notre part, il est essentiel de trouver une solution qui réponde aux besoins de chacun.&#60;/p&#62;\r\n&#60;p&#62;Pour cela, nous vous proposons d\'organiser une &#60;strong&#62;courte réunion de 15 minutes&#60;/strong&#62; avec vous deux et un membre de notre équipe. L\'objectif sera de décider ensemble de la meilleure marche à suivre.&#60;/p&#62;\r\n&#60;p&#62;Dans l\'attente de cet échange, nous allons &#60;strong&#62;maintenir le serveur Zefyr actif&#60;/strong&#62; et ne procéderons à aucune suppression.&#60;/p&#62;\r\n&#60;p&#62;Pourriez-vous nous indiquer vos disponibilités communes pour cette semaine ?&#60;/p&#62;\r\n&#60;p&#62;&#60;strong&#62;Cordialement,&#60;/strong&#62; &#60;strong&#62;L\'équipe de support informatique.&#60;/strong&#62;&#60;/p&#62;',0,2,'2025-10-16 13:48:52','2025-10-16 13:48:52',1,0,0),
(3,'Ticket',2,'2025-10-16 13:49:12',2,0,'&#60;p&#62;Bonjour Steeve,&#60;/p&#62;\r\n&#60;p&#62;Pour assurer une communication transparente, la réponse à votre demande et à celle de Raphaël a été centralisée sur le ticket N°1, auquel vous avez été ajouté en observateur.&#60;/p&#62;\r\n&#60;p&#62;Ce ticket est maintenant lié et en attente de la planification de la réunion.&#60;/p&#62;\r\n&#60;p&#62;Cordialement, L\'équipe de support informatique.&#60;/p&#62;',0,2,'2025-10-16 13:49:12','2025-10-16 13:49:12',1,0,0),
(4,'Ticket',11,'2025-10-16 14:13:37',2,0,'&#60;p&#62;&#60;strong&#62;Bonjour Samuel,&#60;/strong&#62;&#60;/p&#62;\r\n&#60;p&#62;Suite à l\'incident de sécurité sur votre poste, nous vous confirmons sa prise en charge complète.&#60;/p&#62;\r\n&#60;p&#62;Votre machine a bien été isolée et est en cours de sécurisation. Pour garantir qu\'aucune menace ne subsiste, nous procédons à une réinstallation complète.&#60;/p&#62;\r\n&#60;p&#62;Un nouvel ordinateur est en cours de préparation et nous vous contacterons dès qu\'il sera prêt.&#60;/p&#62;\r\n&#60;p&#62;Merci pour votre réactivité qui a été essentielle pour contenir la menace.&#60;/p&#62;\r\n&#60;p&#62;&#60;strong&#62;Cordialement,&#60;/strong&#62; &#60;strong&#62;L\'équipe de support informatique.&#60;/strong&#62;&#60;/p&#62;',0,2,'2025-10-16 14:13:37','2025-10-16 14:13:37',1,0,0),
(5,'Ticket',11,'2025-10-16 14:21:50',2,0,'&#60;p&#62;&#60;strong&#62;Bonjour Samuel,&#60;/strong&#62;&#60;/p&#62;\r\n&#60;p&#62;Votre nouveau poste de travail, entièrement sécurisé et réinstallé, est maintenant opérationnel.&#60;/p&#62;\r\n&#60;p&#62;Pourriez-vous s\'il vous plaît prendre un moment pour &#60;strong&#62;confirmer que vous avez bien accès à tous vos logiciels et que vos données essentielles ont été restaurées&#60;/strong&#62; ?&#60;/p&#62;\r\n&#60;p&#62;Votre confirmation nous permettra de clore cet incident. Nous restons à votre disposition si vous constatez le moindre problème.&#60;/p&#62;\r\n&#60;p&#62;&#60;strong&#62;Cordialement,&#60;/strong&#62; &#60;strong&#62;L\'équipe de support informatique.&#60;/strong&#62;&#60;/p&#62;',0,2,'2025-10-16 14:21:50','2025-10-16 14:21:50',1,0,0),
(6,'Ticket',4,'2025-10-16 14:48:03',2,0,'&#60;p&#62;&#60;strong&#62;Bonjour Élise,&#60;/strong&#62;&#60;/p&#62;\r\n&#60;p&#62;Suite à votre demande concernant la mise en place d\'un accès VPN avec notre partenaire Ocito, nous vous confirmons la prise en charge de ce projet.&#60;/p&#62;\r\n&#60;p&#62;Nous avons initié ce jour le contact avec leur équipe technique pour lancer le processus de configuration du VPN. La mise en place effective dépendra de leur réactivité.&#60;/p&#62;\r\n&#60;p&#62;Nous vous tiendrons informée de l\'avancement et reviendrons vers vous pour planifier les tests de connexion dès que possible.&#60;/p&#62;\r\n&#60;p&#62;&#60;strong&#62;Cordialement,&#60;/strong&#62; &#60;strong&#62;L\'équipe de support informatique.&#60;/strong&#62;&#60;/p&#62;',0,2,'2025-10-16 14:48:03','2025-10-16 14:48:03',1,0,0);
INSERT INTO `glpi_itilsolutions` VALUES
(1,'Ticket',11,0,NULL,'&#60;p&#62;Poste de travail compromis suite à l\'ouverture d\'une pièce jointe malveillante. Risque de propagation élevé.&#60;/p&#62;\r\n&#60;blockquote&#62;\r\n&#60;p&#62;&#60;strong&#62;Actions menées :&#60;/strong&#62;&#60;/p&#62;\r\n&#60;ol start=\"1\"&#62;\r\n&#60;li&#62;\r\n&#60;p&#62;Le poste a été immédiatement isolé du réseau (N1).&#60;/p&#62;\r\n&#60;/li&#62;\r\n&#60;li&#62;\r\n&#60;p&#62;Un poste de prêt a été fourni à l\'utilisateur (N1).&#60;/p&#62;\r\n&#60;/li&#62;\r\n&#60;li&#62;\r\n&#60;p&#62;Le poste infecté a été pris en charge pour un reformatage complet et une réinstallation à partir d\'une image saine (N2).&#60;/p&#62;\r\n&#60;/li&#62;\r\n&#60;li&#62;\r\n&#60;p&#62;Le mot de passe de l\'utilisateur a été réinitialisé par mesure de précaution.&#60;/p&#62;\r\n&#60;/li&#62;\r\n&#60;li&#62;\r\n&#60;p&#62;La procédure &#60;strong&#62;\"&#60;span style=\"color: #000000; font-family: inter, -apple-system, blinkmacsystemfont, \'san francisco\', \'segoe ui\', roboto, \'helvetica neue\', sans-serif; font-size: 14px; font-style: normal; font-variant-ligatures: no-contextual; font-variant-caps: normal; letter-spacing: normal; orphans: 2; text-align: start; text-indent: 0px; text-transform: none; widows: 2; word-spacing: 0px; -webkit-text-stroke-width: 0px; white-space: normal; background-color: rgba(98, 105, 118, 0.1); float: none; display: inline !important;\"&#62;Procédure Technique : Gestion d\'un poste de travail suspecté d\'infection Version : 1.0&#60;/span&#62;\"&#60;/strong&#62; a été rédigée et ajoutée à la base de connaissances.&#60;/p&#62;\r\n&#60;/li&#62;\r\n&#60;li&#62;\r\n&#60;p&#62;Un suivi a été envoyé à l\'utilisateur pour l\'informer de la situation.&#60;/p&#62;\r\n&#60;/li&#62;\r\n&#60;/ol&#62;\r\n&#60;/blockquote&#62;','2025-10-16 14:17:32','2025-10-16 14:18:17','2025-10-16 14:18:02',2,NULL,2,2,NULL,4,NULL),
(2,'Ticket',3,0,NULL,'&#60;div id=\"model-response-message-contentr_61303089d5aa52bc\" class=\"markdown markdown-main-panel stronger enable-updated-hr-color\" dir=\"ltr\" style=\"--animation-duration: 400ms; --fade-animation-function: linear;\"&#62;\r\n&#60;p&#62;&#60;strong&#62;Bonjour Sophie,&#60;/strong&#62;&#60;/p&#62;\r\n&#60;p&#62;Suite à votre signalement concernant l\'e-mail suspect, nous avons analysé la situation et nous vous remercions vivement pour votre vigilance.&#60;/p&#62;\r\n&#60;p&#62;Vous avez eu le bon réflexe : il s\'agit bien d\'une tentative de \"phishing\" (hameçonnage). Votre prudence a permis d\'écarter tout risque.&#60;/p&#62;\r\n&#60;p&#62;Voici la procédure à suivre immédiatement :&#60;/p&#62;\r\n&#60;ol start=\"1\"&#62;\r\n&#60;li&#62;\r\n&#60;p&#62;&#60;strong&#62;Ne répondez surtout pas&#60;/strong&#62; à cet e-mail et ne cliquez sur aucun lien.&#60;/p&#62;\r\n&#60;/li&#62;\r\n&#60;li&#62;\r\n&#60;p&#62;&#60;strong&#62;Supprimez définitivement l\'e-mail&#60;/strong&#62; de votre boîte de réception, puis de votre corbeille.&#60;/p&#62;\r\n&#60;/li&#62;\r\n&#60;/ol&#62;\r\n&#60;p&#62;Pour vous aider, ainsi que vos collègues, à mieux identifier ces menaces à l\'avenir, &#60;strong&#62;vous pouvez consulter le guide complet que nous avons mis à disposition dans notre base de connaissances.&#60;/strong&#62;&#60;/p&#62;\r\n&#60;p&#62;N\'hésitez jamais à nous contacter au moindre doute. Votre rôle est essentiel pour la sécurité de tous.&#60;/p&#62;\r\n&#60;p&#62;&#60;strong&#62;Cordialement,&#60;/strong&#62; &#60;strong&#62;L\'équipe de support informatique.&#60;/strong&#62;&#60;/p&#62;\r\n&#60;/div&#62;\r\n&#60;p&#62; &#60;/p&#62;','2025-10-16 14:40:02','2025-10-16 14:40:02',NULL,2,NULL,0,0,NULL,2,NULL),
(3,'Ticket',5,0,NULL,'&#60;p&#62;&#60;strong&#62;Bonjour Charly,&#60;/strong&#62;&#60;/p&#62;\r\n&#60;p&#62;Suite à votre demande concernant votre impossibilité de vous connecter, nous avons analysé la situation. Votre compte utilisateur était temporairement verrouillé.&#60;/p&#62;\r\n&#60;p&#62;Nous avons procédé à sa réinitialisation. Voici la procédure pour vous reconnecter :&#60;/p&#62;\r\n&#60;ol start=\"1\"&#62;\r\n&#60;li&#62;\r\n&#60;p&#62;Utilisez le mot de passe temporaire suivant : &#60;strong&#62;&#60;code&#62;]6x%Bw59wy3X+N&#60;/code&#62;&#60;/strong&#62;&#60;/p&#62;\r\n&#60;/li&#62;\r\n&#60;li&#62;\r\n&#60;p&#62;À votre première connexion, le système vous demandera obligatoirement de choisir un nouveau mot de passe personnel et confidentiel.&#60;/p&#62;\r\n&#60;/li&#62;\r\n&#60;/ol&#62;\r\n&#60;p&#62;Après cette étape, votre accès sera de nouveau pleinement fonctionnel.&#60;/p&#62;\r\n&#60;p&#62;N\'hésitez pas à nous recontacter si le problème persiste.&#60;/p&#62;\r\n&#60;p&#62;&#60;strong&#62;Cordialement,&#60;/strong&#62; &#60;strong&#62;L\'équipe de support informatique.&#60;/strong&#62;&#60;/p&#62;','2025-10-16 14:54:02','2025-10-16 14:54:02',NULL,2,NULL,0,0,NULL,2,NULL),
(4,'Ticket',6,0,NULL,'&#60;p&#62;&#60;strong&#62;Bonjour René,&#60;/strong&#62;&#60;/p&#62;\r\n&#60;p&#62;Suite à votre demande, et pour donner suite à votre excellente initiative, nous avons le plaisir de vous annoncer que le &#60;strong&#62;\"Guide Pratique de l\'IA pour les Développeurs\"&#60;/strong&#62; est désormais finalisé.&#60;/p&#62;\r\n&#60;p&#62;Vous le trouverez disponible dans notre base de connaissances GLPI (Catégorie IA).&#60;/p&#62;\r\n&#60;p&#62;Ce guide a été conçu pour vous et votre équipe. Il met l\'accent sur le point le plus crucial – &#60;strong&#62;la sécurité de nos données&#60;/strong&#62; – et vous y trouverez des exemples de scripts et des conseils pratiques pour tirer le meilleur parti de ces nouveaux outils.&#60;/p&#62;\r\n&#60;p&#62;Nous sommes convaincus que cela vous aidera à accélérer vos développements de manière innovante et sécurisée.&#60;/p&#62;\r\n&#60;p&#62;N\'hésitez pas à nous faire un retour après l\'avoir consulté.&#60;/p&#62;\r\n&#60;p&#62;&#60;strong&#62;Cordialement,&#60;/strong&#62;&#60;/p&#62;\r\n&#60;p&#62;&#60;strong&#62;L\'équipe de support informatique.&#60;/strong&#62;&#60;/p&#62;','2025-10-16 15:47:02','2025-10-16 15:47:02',NULL,2,NULL,0,0,NULL,2,NULL);
