INSERT INTO `glpi_knowbaseitems` VALUES
(1,'Procédure Technique : Gestion d\'un poste de travail suspecté d\'infection Version : 1.0','&#60;p&#62;&#60;strong&#62;Table des Matières :&#60;/strong&#62;&#60;/p&#62;\r\n&#60;ol start=\"1\"&#62;\r\n&#60;li&#62;\r\n&#60;p&#62;Objectif et Champ d\'application&#60;/p&#62;\r\n&#60;/li&#62;\r\n&#60;li&#62;\r\n&#60;p&#62;Phase 1 : Identification et Réflexe Immédiat (Action Utilisateur / Support N1)&#60;/p&#62;\r\n&#60;/li&#62;\r\n&#60;li&#62;\r\n&#60;p&#62;Phase 2 : Confinement et Remplacement (Action Support N1)&#60;/p&#62;\r\n&#60;/li&#62;\r\n&#60;li&#62;\r\n&#60;p&#62;Phase 3 : Éradication et Préparation (Action Support N2)&#60;/p&#62;\r\n&#60;/li&#62;\r\n&#60;li&#62;\r\n&#60;p&#62;Phase 4 : Restauration et Clôture (Action Support N1/N2)&#60;/p&#62;\r\n&#60;/li&#62;\r\n&#60;/ol&#62;\r\n&#60;hr&#62;\r\n&#60;p&#62; &#60;/p&#62;\r\n&#60;h3&#62;&#60;strong&#62;1. Objectif et Champ d\'application&#60;/strong&#62;&#60;/h3&#62;\r\n&#60;p&#62; &#60;/p&#62;\r\n&#60;p&#62;Ce document détaille la procédure obligatoire à suivre pour tout poste de travail (utilisateur) suspecté d\'être infecté par un logiciel malveillant (virus, rançongiciel, cheval de Troie, etc.). L\'objectif principal est de &#60;strong&#62;protéger l\'intégrité du système d\'information de l\'entreprise&#60;/strong&#62; en contenant la menace, en l\'éradiquant de manière fiable et en restaurant le service à l\'utilisateur dans les meilleurs délais.&#60;/p&#62;\r\n&#60;p&#62;&#60;strong&#62;Principe fondamental :&#60;/strong&#62; Un poste suspect est considéré comme &#60;strong&#62;non fiable&#60;/strong&#62;, même si l\'antivirus déployé ne signale aucune alerte active.&#60;/p&#62;\r\n&#60;p&#62; &#60;/p&#62;\r\n&#60;h3&#62;&#60;strong&#62;2. Phase 1 : Identification et Réflexe Immédiat (Action Utilisateur / Support N1)&#60;/strong&#62;&#60;/h3&#62;\r\n&#60;p&#62; &#60;/p&#62;\r\n&#60;p&#62;Dès qu\'une suspicion est avérée (comportement anormal, message d\'erreur, perte d\'accès aux applications suite à l\'ouverture d\'un fichier), l\'action immédiate est &#60;strong&#62;le confinement.&#60;/strong&#62;&#60;/p&#62;\r\n&#60;ol start=\"1\"&#62;\r\n&#60;li&#62;\r\n&#60;p&#62;&#60;strong&#62;Action la plus importante : ISOLER LE POSTE DU RÉSEAU.&#60;/strong&#62;&#60;/p&#62;\r\n&#60;ul&#62;\r\n&#60;li&#62;\r\n&#60;p&#62;&#60;strong&#62;Débrancher physiquement le câble réseau (Ethernet).&#60;/strong&#62;&#60;/p&#62;\r\n&#60;/li&#62;\r\n&#60;li&#62;\r\n&#60;p&#62;&#60;strong&#62;Désactiver le Wi-Fi&#60;/strong&#62; via les paramètres ou le bouton physique de l\'ordinateur.&#60;/p&#62;\r\n&#60;/li&#62;\r\n&#60;li&#62;\r\n&#60;p&#62;&#60;strong&#62;NE PAS ÉTEINDRE&#60;/strong&#62; l\'ordinateur, sauf instruction contraire du N2 (pour préserver une éventuelle analyse mémoire).&#60;/p&#62;\r\n&#60;/li&#62;\r\n&#60;/ul&#62;\r\n&#60;/li&#62;\r\n&#60;li&#62;\r\n&#60;p&#62;&#60;strong&#62;NE TENTER AUCUNE RÉPARATION.&#60;/strong&#62; Ne pas lancer de scan antivirus, ne pas essayer de supprimer des fichiers, ne pas tenter de se reconnecter à des services. Toute action pourrait aggraver la situation ou alerter l\'attaquant.&#60;/p&#62;\r\n&#60;/li&#62;\r\n&#60;li&#62;\r\n&#60;p&#62;&#60;strong&#62;Contacter immédiatement le support informatique&#60;/strong&#62; par téléphone en décrivant précisément les symptômes et la dernière action effectuée (ex: \"J\'ai ouvert un devis et depuis je n\'ai plus accès à mes mails\").&#60;/p&#62;\r\n&#60;/li&#62;\r\n&#60;/ol&#62;\r\n&#60;p&#62; &#60;/p&#62;\r\n&#60;h3&#62;&#60;strong&#62;3. Phase 2 : Confinement et Remplacement (Action Support N1)&#60;/strong&#62;&#60;/h3&#62;\r\n&#60;p&#62; &#60;/p&#62;\r\n&#60;p&#62;Le rôle du technicien de Niveau 1 est de finaliser le confinement et d\'assurer la continuité de service pour l\'utilisateur.&#60;/p&#62;\r\n&#60;ol start=\"1\"&#62;\r\n&#60;li&#62;\r\n&#60;p&#62;&#60;strong&#62;Se rendre sur place&#60;/strong&#62; pour confirmer l\'isolement réseau de la machine.&#60;/p&#62;\r\n&#60;/li&#62;\r\n&#60;li&#62;\r\n&#60;p&#62;&#60;strong&#62;Ne pas se connecter au poste&#60;/strong&#62; avec un compte administrateur.&#60;/p&#62;\r\n&#60;/li&#62;\r\n&#60;li&#62;\r\n&#60;p&#62;&#60;strong&#62;Récupérer le poste infecté&#60;/strong&#62; et l\'étiqueter clairement comme \"EN QUARANTAINE - NE PAS CONNECTER AU RÉSEAU\".&#60;/p&#62;\r\n&#60;/li&#62;\r\n&#60;li&#62;\r\n&#60;p&#62;&#60;strong&#62;Fournir un poste de prêt&#60;/strong&#62; à l\'utilisateur pour qu\'il puisse reprendre son activité au plus vite.&#60;/p&#62;\r\n&#60;/li&#62;\r\n&#60;li&#62;\r\n&#60;p&#62;&#60;strong&#62;Escalader le ticket au Niveau 2&#60;/strong&#62; avec toutes les informations collectées.&#60;/p&#62;\r\n&#60;/li&#62;\r\n&#60;/ol&#62;\r\n&#60;p&#62; &#60;/p&#62;\r\n&#60;h3&#62;&#60;strong&#62;4. Phase 3 : Éradication et Préparation (Action Support N2)&#60;/strong&#62;&#60;/h3&#62;\r\n&#60;p&#62; &#60;/p&#62;\r\n&#60;p&#62;Le rôle du Niveau 2 est d\'éradiquer la menace de manière définitive et sécurisée.&#60;/p&#62;\r\n&#60;ol start=\"1\"&#62;\r\n&#60;li&#62;\r\n&#60;p&#62;&#60;strong&#62;Sauvegarde des données (optionnelle et sécurisée) :&#60;/strong&#62; Si les données de l\'utilisateur ne sont pas synchronisées sur un serveur, connecter le disque dur du poste infecté en externe sur une &#60;strong&#62;machine d\'analyse isolée (sandbox)&#60;/strong&#62; qui n\'est pas connectée au réseau de production.&#60;/p&#62;\r\n&#60;ul&#62;\r\n&#60;li&#62;\r\n&#60;p&#62;Effectuer un scan antivirus approfondi des fichiers.&#60;/p&#62;\r\n&#60;/li&#62;\r\n&#60;li&#62;\r\n&#60;p&#62;Copier &#60;strong&#62;UNIQUEMENT les fichiers utilisateurs&#60;/strong&#62; (.docx, .xlsx, .pdf, etc.) sur un support externe. Ne jamais copier d\'exécutables, de fichiers système ou de profils applicatifs.&#60;/p&#62;\r\n&#60;/li&#62;\r\n&#60;/ul&#62;\r\n&#60;/li&#62;\r\n&#60;li&#62;\r\n&#60;p&#62;&#60;strong&#62;Éradication par réinstallation complète :&#60;/strong&#62; La seule méthode fiable est le reformatage.&#60;/p&#62;\r\n&#60;ul&#62;\r\n&#60;li&#62;\r\n&#60;p&#62;&#60;strong&#62;Effacer complètement le disque dur&#60;/strong&#62; (formatage bas niveau si possible).&#60;/p&#62;\r\n&#60;/li&#62;\r\n&#60;li&#62;\r\n&#60;p&#62;&#60;strong&#62;Réinstaller le système d\'exploitation&#60;/strong&#62; à partir d\'une image \"master\" saine et validée par le service IT.&#60;/p&#62;\r\n&#60;/li&#62;\r\n&#60;/ul&#62;\r\n&#60;/li&#62;\r\n&#60;li&#62;\r\n&#60;p&#62;&#60;strong&#62;Préparation du nouveau poste :&#60;/strong&#62;&#60;/p&#62;\r\n&#60;ul&#62;\r\n&#60;li&#62;\r\n&#60;p&#62;Installer l\'ensemble des logiciels de l\'entreprise.&#60;/p&#62;\r\n&#60;/li&#62;\r\n&#60;li&#62;\r\n&#60;p&#62;S\'assurer que l\'antivirus est à jour et fonctionnel.&#60;/p&#62;\r\n&#60;/li&#62;\r\n&#60;li&#62;\r\n&#60;p&#62;Effectuer toutes les mises à jour système et logicielles.&#60;/p&#62;\r\n&#60;/li&#62;\r\n&#60;/ul&#62;\r\n&#60;/li&#62;\r\n&#60;/ol&#62;\r\n&#60;p&#62; &#60;/p&#62;\r\n&#60;h3&#62;&#60;strong&#62;5. Phase 4 : Restauration et Clôture (Action Support N1/N2)&#60;/strong&#62;&#60;/h3&#62;\r\n&#60;p&#62; &#60;/p&#62;\r\n&#60;ol start=\"1\"&#62;\r\n&#60;li&#62;\r\n&#60;p&#62;&#60;strong&#62;Réinitialisation des identifiants :&#60;/strong&#62; Le compte de l\'utilisateur (exemple: Active Directory.) doit être considéré comme compromis. &#60;strong&#62;Réinitialiser son mot de passe immédiatement.&#60;/strong&#62; Lui communiquer un mot de passe temporaire avec obligation de le changer à la première connexion.&#60;/p&#62;\r\n&#60;/li&#62;\r\n&#60;li&#62;\r\n&#60;p&#62;&#60;strong&#62;Livrer le nouveau poste&#60;/strong&#62; à l\'utilisateur.&#60;/p&#62;\r\n&#60;/li&#62;\r\n&#60;li&#62;\r\n&#60;p&#62;&#60;strong&#62;Restaurer les données utilisateurs&#60;/strong&#62; qui ont été sauvegardées et vérifiées.&#60;/p&#62;\r\n&#60;/li&#62;\r\n&#60;li&#62;\r\n&#60;p&#62;&#60;strong&#62;Confirmer avec l\'utilisateur&#60;/strong&#62; que ses accès sont de nouveau fonctionnels et que ses données essentielles sont présentes.&#60;/p&#62;\r\n&#60;/li&#62;\r\n&#60;li&#62;\r\n&#60;p&#62;&#60;strong&#62;Clôturer le ticket GLPI&#60;/strong&#62; en documentant toutes les étapes dans la solution.&#60;/p&#62;\r\n&#60;/li&#62;\r\n&#60;/ol&#62;',1,2,7,'2025-10-16 14:09:41','2025-10-16 14:09:41','2025-10-16 16:05:08',NULL),
(2,'Sécurité : Identifier et réagir face à une tentative de phishing Version : 1.1','&#60;h3&#62;&#60;strong&#62;Table des Matières :&#60;/strong&#62;&#60;/h3&#62;\r\n&#60;p&#62; &#60;/p&#62;\r\n&#60;ol start=\"1\"&#62;\r\n&#60;li&#62;\r\n&#60;p&#62;Qu\'est-ce que le phishing ?&#60;/p&#62;\r\n&#60;/li&#62;\r\n&#60;li&#62;\r\n&#60;p&#62;Les 5 indices qui doivent vous alerter&#60;/p&#62;\r\n&#60;/li&#62;\r\n&#60;li&#62;\r\n&#60;p&#62;La procédure officielle à suivre&#60;/p&#62;\r\n&#60;/li&#62;\r\n&#60;li&#62;\r\n&#60;p&#62;J\'ai cliqué sur un lien, que faire ?&#60;/p&#62;\r\n&#60;/li&#62;\r\n&#60;li&#62;\r\n&#60;p&#62;Conclusion : Les bonnes pratiques à retenir&#60;/p&#62;\r\n&#60;/li&#62;\r\n&#60;/ol&#62;\r\n&#60;hr&#62;\r\n&#60;p&#62; &#60;/p&#62;\r\n&#60;h3&#62;&#60;strong&#62;1. Qu\'est-ce que le phishing ?&#60;/strong&#62; 🎣&#60;/h3&#62;\r\n&#60;p&#62; &#60;/p&#62;\r\n&#60;p&#62;Le phishing (ou hameçonnage) est une technique de fraude visant à vous tromper pour vous voler des informations (mots de passe, données bancaires) ou vous faire réaliser une action (un virement). Les fraudeurs se font passer pour une personne ou une entité de confiance (banque, transporteur, fournisseur, etc.). Un seul clic peut suffire à compromettre la sécurité de toute l\'entreprise.&#60;/p&#62;\r\n&#60;hr&#62;\r\n&#60;p&#62; &#60;/p&#62;\r\n&#60;h3&#62;&#60;strong&#62;2. Les 5 indices qui doivent vous alerter&#60;/strong&#62;&#60;/h3&#62;\r\n&#60;p&#62; &#60;/p&#62;\r\n&#60;p&#62;Voici les signes qui doivent immédiatement attirer votre attention. Pour illustrer, imaginons un faux e-mail de livraison :&#60;/p&#62;\r\n&#60;ul&#62;\r\n&#60;li&#62;\r\n&#60;p&#62;&#60;strong&#62;L\'expéditeur :&#60;/strong&#62; L\'adresse e-mail est souvent très similaire à une vraie, mais légèrement différente.&#60;/p&#62;\r\n&#60;ul&#62;\r\n&#60;li&#62;\r\n&#60;p&#62;&#60;em&#62;Exemple :&#60;/em&#62; &#60;code&#62;livraisons@open-showroom.com&#60;/code&#62; au lieu de l\'adresse officielle &#60;code&#62;livraisons@openshowroom.com&#60;/code&#62;.&#60;/p&#62;\r\n&#60;/li&#62;\r\n&#60;/ul&#62;\r\n&#60;/li&#62;\r\n&#60;li&#62;\r\n&#60;p&#62;&#60;strong&#62;Le ton :&#60;/strong&#62; Le message est souvent pressant, inhabituel ou menaçant pour vous faire agir sans réfléchir.&#60;/p&#62;\r\n&#60;ul&#62;\r\n&#60;li&#62;\r\n&#60;p&#62;&#60;em&#62;Exemple :&#60;/em&#62; \"Votre compte sera suspendu sous 24h\", \"Virement urgent à effectuer avant midi\".&#60;/p&#62;\r\n&#60;/li&#62;\r\n&#60;/ul&#62;\r\n&#60;/li&#62;\r\n&#60;li&#62;\r\n&#60;p&#62;&#60;strong&#62;Les fautes :&#60;/strong&#62; Les communications officielles sont généralement soignées. La présence de fautes d\'orthographe ou de grammaire est un indice majeur.&#60;/p&#62;\r\n&#60;/li&#62;\r\n&#60;li&#62;\r\n&#60;p&#62;&#60;strong&#62;Les liens :&#60;/strong&#62; En survolant un lien avec votre souris (&#60;strong&#62;sans cliquer !&#60;/strong&#62;), l\'adresse qui s\'affiche est souvent suspecte ou ne correspond pas au site attendu.&#60;/p&#62;\r\n&#60;/li&#62;\r\n&#60;li&#62;\r\n&#60;p&#62;&#60;strong&#62;La demande :&#60;/strong&#62; On vous demande une action inhabituelle ou confidentielle.&#60;/p&#62;\r\n&#60;ul&#62;\r\n&#60;li&#62;\r\n&#60;p&#62;&#60;em&#62;Exemple :&#60;/em&#62; Changer les coordonnées bancaires d\'un fournisseur, fournir votre mot de passe.&#60;/p&#62;\r\n&#60;/li&#62;\r\n&#60;/ul&#62;\r\n&#60;/li&#62;\r\n&#60;/ul&#62;\r\n&#60;hr&#62;\r\n&#60;p&#62; &#60;/p&#62;\r\n&#60;h3&#62;&#60;strong&#62;3. La procédure officielle à suivre&#60;/strong&#62;&#60;/h3&#62;\r\n&#60;p&#62; &#60;/p&#62;\r\n&#60;p&#62;Si vous avez le moindre doute sur un e-mail :&#60;/p&#62;\r\n&#60;ol start=\"1\"&#62;\r\n&#60;li&#62;\r\n&#60;p&#62;&#60;strong&#62;STOP : Ne cliquez sur RIEN.&#60;/strong&#62; Ne répondez pas, ne téléchargez aucune pièce jointe.&#60;/p&#62;\r\n&#60;/li&#62;\r\n&#60;li&#62;\r\n&#60;p&#62;&#60;strong&#62;SIGNALER :&#60;/strong&#62; Transférez immédiatement l\'e-mail au &#60;strong&#62;support informatique&#60;/strong&#62;. Cela nous permet d\'analyser la menace.&#60;/p&#62;\r\n&#60;/li&#62;\r\n&#60;li&#62;\r\n&#60;p&#62;&#60;strong&#62;SUPPRIMER :&#60;/strong&#62; Une fois transféré, supprimez définitivement l\'e-mail de votre messagerie.&#60;/p&#62;\r\n&#60;/li&#62;\r\n&#60;/ol&#62;\r\n&#60;hr&#62;\r\n&#60;p&#62; &#60;/p&#62;\r\n&#60;h3&#62;&#60;strong&#62;4. J\'ai cliqué sur un lien, que faire ?&#60;/strong&#62;&#60;/h3&#62;\r\n&#60;p&#62; &#60;/p&#62;\r\n&#60;p&#62;Si vous avez cliqué par erreur, il faut agir très vite pour limiter les dégâts :&#60;/p&#62;\r\n&#60;ol start=\"1\"&#62;\r\n&#60;li&#62;\r\n&#60;p&#62;&#60;strong&#62;Déconnectez immédiatement&#60;/strong&#62; votre ordinateur du réseau (coupez le Wi-Fi ou débranchez le câble Ethernet).&#60;/p&#62;\r\n&#60;/li&#62;\r\n&#60;li&#62;\r\n&#60;p&#62;&#60;strong&#62;Contactez d\'urgence le support informatique&#60;/strong&#62; par téléphone. Ne reconnectez pas votre machine avant d\'avoir notre accord.&#60;/p&#62;\r\n&#60;/li&#62;\r\n&#60;/ol&#62;\r\n&#60;hr&#62;\r\n&#60;p&#62; &#60;/p&#62;\r\n&#60;h3&#62;&#60;strong&#62;5. Conclusion : Les bonnes pratiques à retenir&#60;/strong&#62;&#60;/h3&#62;\r\n&#60;p&#62; &#60;/p&#62;\r\n&#60;ul&#62;\r\n&#60;li&#62;\r\n&#60;p&#62;&#60;strong&#62;Soyez sceptique :&#60;/strong&#62; Si un e-mail vous semble étrange, il l\'est probablement.&#60;/p&#62;\r\n&#60;/li&#62;\r\n&#60;li&#62;\r\n&#60;p&#62;&#60;strong&#62;Vérifiez par un autre canal :&#60;/strong&#62; Pour toute demande importante (virement, changement de RIB), appelez votre contact habituel pour confirmer.&#60;/p&#62;\r\n&#60;/li&#62;\r\n&#60;li&#62;\r\n&#60;p&#62;&#60;strong&#62;En cas de doute, le seul bon réflexe est de nous contacter.&#60;/strong&#62;&#60;/p&#62;\r\n&#60;/li&#62;\r\n&#60;/ul&#62;',1,2,6,'2025-10-16 14:35:21','2025-10-16 15:42:03','2025-10-16 16:32:58',NULL),
(3,'Guide Pratique de l\'IA pour les Développeurs Version : 1.0','&#60;h3&#62;&#60;strong&#62;Table des Matières :&#60;/strong&#62;&#60;/h3&#62;\r\n&#60;p&#62; &#60;/p&#62;\r\n&#60;ol start=\"1\"&#62;\r\n&#60;li&#62;\r\n&#60;p&#62;Introduction : L\'IA, votre nouveau co-pilote&#60;/p&#62;\r\n&#60;/li&#62;\r\n&#60;li&#62;\r\n&#60;p&#62;Cas d\'Usage Concrets : Quand l\'IA fait la Différence&#60;/p&#62;\r\n&#60;/li&#62;\r\n&#60;li&#62;\r\n&#60;p&#62;Exemples Pratiques : L\'IA en Action&#60;/p&#62;\r\n&#60;/li&#62;\r\n&#60;li&#62;\r\n&#60;p&#62;Règles d\'Or : Bonnes Pratiques et Points de Vigilance Essentiels&#60;/p&#62;\r\n&#60;/li&#62;\r\n&#60;/ol&#62;\r\n&#60;hr&#62;\r\n&#60;p&#62; &#60;/p&#62;\r\n&#60;h3&#62;&#60;strong&#62;1. Introduction : L\'IA, votre nouveau co-pilote&#60;/strong&#62;&#60;/h3&#62;\r\n&#60;p&#62;Imaginez un assistant de programmation qui ne dort jamais, connaît des milliers de bibliothèques et vous aide à écrire du bon code, plus rapidement. C\'est exactement ce que l\'intelligence artificielle apporte aujourd\'hui aux développeurs du monde entier. Ce guide a pour objectif de montrer comment utiliser l\'IA pour automatiser les tâches répétitives et se concentrer sur la résolution de problèmes et la création d\'applications.&#60;/p&#62;\r\n&#60;p&#62; &#60;/p&#62;\r\n&#60;h3&#62;&#60;strong&#62;2. Cas d\'Usage Concrets : Quand l\'IA fait la Différence&#60;/strong&#62;&#60;/h3&#62;\r\n&#60;p&#62;L\'IA peut intervenir à presque toutes les étapes du cycle de développement. Voici les scénarios où elle excelle :&#60;/p&#62;\r\n&#60;ul&#62;\r\n&#60;li&#62;\r\n&#60;p&#62;&#60;strong&#62;Génération de Code :&#60;/strong&#62; L\'IA analyse le contexte pour suggérer des lignes, des fonctions entières, voire des classes complètes, réduisant le temps de frappe et les erreurs de syntaxe.&#60;/p&#62;\r\n&#60;/li&#62;\r\n&#60;li&#62;\r\n&#60;p&#62;&#60;strong&#62;Analyse de Données :&#60;/strong&#62; Elle peut parcourir des milliers de lignes de fichiers pour extraire des informations clés, identifier des anomalies ou résumer des tendances automatiquement.&#60;/p&#62;\r\n&#60;/li&#62;\r\n&#60;li&#62;\r\n&#60;p&#62;&#60;strong&#62;Refactoring :&#60;/strong&#62; Elle transforme du code fonctionnel en une version optimisée, plus performante, plus lisible et conforme aux standards du langage.&#60;/p&#62;\r\n&#60;/li&#62;\r\n&#60;li&#62;\r\n&#60;p&#62;&#60;strong&#62;Tests Unitaires :&#60;/strong&#62; Elle crée automatiquement une base solide de tests pour vos fonctions, couvrant les cas nominaux, les cas limites et la gestion des erreurs.&#60;/p&#62;\r\n&#60;/li&#62;\r\n&#60;li&#62;\r\n&#60;p&#62;&#60;strong&#62;Automatisation :&#60;/strong&#62; Elle peut générer des scripts pour automatiser la classification de tickets, les réponses standards ou la création de rapports périodiques.&#60;/p&#62;\r\n&#60;/li&#62;\r\n&#60;/ul&#62;\r\n&#60;p&#62; &#60;/p&#62;\r\n&#60;h3&#62;&#60;strong&#62;3. Exemples Pratiques : L\'IA en Action&#60;/strong&#62;&#60;/h3&#62;\r\n&#60;h4&#62;&#60;strong&#62;a) Génération et Auto-complétion de Code 🤖&#60;/strong&#62;&#60;/h4&#62;\r\n&#60;ul&#62;\r\n&#60;li&#62;\r\n&#60;p&#62;&#60;strong&#62;Objectif :&#60;/strong&#62; Transformer une simple instruction en français en un bloc de code fonctionnel.&#60;/p&#62;\r\n&#60;/li&#62;\r\n&#60;li&#62;\r\n&#60;p&#62;&#60;strong&#62;Fonctionnement :&#60;/strong&#62; Dans un éditeur comme VS Code avec Copilot ou Cursor, écrivez un commentaire décrivant l\'action souhaitée.&#60;/p&#62;\r\n&#60;/li&#62;\r\n&#60;/ul&#62;\r\n&#60;p&#62;&#60;strong&#62;1. Vous écrivez le commentaire :&#60;/strong&#62;&#60;/p&#62;\r\n&#60;h3&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;/h3&#62;\r\n&#60;div class=\"code-block ng-tns-c3523328237-392 ng-animate-disabled ng-trigger ng-trigger-codeBlockRevealAnimation\" style=\"display: block;\" data-hveid=\"0\" data-ved=\"0CAAQhtANahgKEwiK7smt46iQAxUAAAAAHQAAAAAQrAY\"&#62;&#60;!----&#62;\r\n&#60;div class=\"formatted-code-block-internal-container ng-tns-c3523328237-392\"&#62;\r\n&#60;div class=\"animated-opacity ng-tns-c3523328237-392\"&#62;\r\n&#60;pre class=\"ng-tns-c3523328237-392\"&#62;&#60;code class=\"code-container formatted ng-tns-c3523328237-392\" role=\"text\" data-test-id=\"code-content\"&#62;&#60;span class=\"hljs-comment\"&#62;# Créer une fonction qui calcule la moyenne d\'une liste de nombres&#60;/span&#62;\r\n&#60;/code&#62;&#60;/pre&#62;\r\n&#60;!----&#62;&#60;/div&#62;\r\n&#60;/div&#62;\r\n&#60;/div&#62;\r\n&#60;h3&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;/h3&#62;\r\n&#60;p&#62;&#60;strong&#62;2. L\'IA génère instantanément le code correspondant :&#60;/strong&#62;&#60;/p&#62;\r\n&#60;h3&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;/h3&#62;\r\n&#60;div class=\"code-block ng-tns-c3523328237-393 ng-animate-disabled ng-trigger ng-trigger-codeBlockRevealAnimation\" style=\"display: block;\" data-hveid=\"0\" data-ved=\"0CAAQhtANahgKEwiK7smt46iQAxUAAAAAHQAAAAAQrQY\"&#62;&#60;!----&#62;\r\n&#60;div class=\"formatted-code-block-internal-container ng-tns-c3523328237-393\"&#62;\r\n&#60;div class=\"animated-opacity ng-tns-c3523328237-393\"&#62;\r\n&#60;pre class=\"ng-tns-c3523328237-393\"&#62;&#60;code class=\"code-container formatted ng-tns-c3523328237-393\" role=\"text\" data-test-id=\"code-content\"&#62;&#60;span class=\"hljs-function\"&#62;&#60;span class=\"hljs-keyword\"&#62;def&#60;/span&#62; &#60;span class=\"hljs-title\"&#62;calculer_moyenne&#60;/span&#62;(&#60;span class=\"hljs-params\"&#62;nombres&#60;/span&#62;):&#60;/span&#62;\r\n    &#60;span class=\"hljs-keyword\"&#62;if&#60;/span&#62; &#60;span class=\"hljs-keyword\"&#62;not&#60;/span&#62; nombres:\r\n        &#60;span class=\"hljs-keyword\"&#62;return&#60;/span&#62; &#60;span class=\"hljs-number\"&#62;0&#60;/span&#62;\r\n    &#60;span class=\"hljs-keyword\"&#62;return&#60;/span&#62; &#60;span class=\"hljs-built_in\"&#62;sum&#60;/span&#62;(nombres) / &#60;span class=\"hljs-built_in\"&#62;len&#60;/span&#62;(nombres)\r\n\r\n&#60;span class=\"hljs-comment\"&#62;# Exemple d\'utilisation&#60;/span&#62;\r\nnotes = [&#60;span class=\"hljs-number\"&#62;15&#60;/span&#62;, &#60;span class=\"hljs-number\"&#62;18&#60;/span&#62;, &#60;span class=\"hljs-number\"&#62;12&#60;/span&#62;, &#60;span class=\"hljs-number\"&#62;16&#60;/span&#62;, &#60;span class=\"hljs-number\"&#62;14&#60;/span&#62;]\r\nmoyenne = calculer_moyenne(notes)\r\nprint(&#60;span class=\"hljs-string\"&#62;f\"Moyenne: &#60;span class=\"hljs-subst\"&#62;{moyenne}&#60;/span&#62;\"&#60;/span&#62;)\r\n&#60;/code&#62;&#60;/pre&#62;\r\n&#60;!----&#62;&#60;/div&#62;\r\n&#60;/div&#62;\r\n&#60;/div&#62;\r\n&#60;h3&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;/h3&#62;\r\n&#60;h4&#62;&#60;strong&#62;b) Génération de Tests Unitaires 🧪&#60;/strong&#62;&#60;/h4&#62;\r\n&#60;ul&#62;\r\n&#60;li&#62;\r\n&#60;p&#62;&#60;strong&#62;Objectif :&#60;/strong&#62; Gagner du temps en générant automatiquement des tests pour une fonction existante.&#60;/p&#62;\r\n&#60;/li&#62;\r\n&#60;/ul&#62;\r\n&#60;p&#62;&#60;strong&#62;I. Voici la fonction que vous souhaitez tester :&#60;/strong&#62;&#60;/p&#62;\r\n&#60;h3&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;/h3&#62;\r\n&#60;div class=\"code-block ng-tns-c3523328237-394 ng-animate-disabled ng-trigger ng-trigger-codeBlockRevealAnimation\" style=\"display: block;\" data-hveid=\"0\" data-ved=\"0CAAQhtANahgKEwiK7smt46iQAxUAAAAAHQAAAAAQrgY\"&#62;&#60;!----&#62;\r\n&#60;div class=\"formatted-code-block-internal-container ng-tns-c3523328237-394\"&#62;\r\n&#60;div class=\"animated-opacity ng-tns-c3523328237-394\"&#62;\r\n&#60;pre class=\"ng-tns-c3523328237-394\"&#62;&#60;code class=\"code-container formatted ng-tns-c3523328237-394\" role=\"text\" data-test-id=\"code-content\"&#62;&#60;span class=\"hljs-function\"&#62;&#60;span class=\"hljs-keyword\"&#62;def&#60;/span&#62; &#60;span class=\"hljs-title\"&#62;calculer_remise&#60;/span&#62;(&#60;span class=\"hljs-params\"&#62;prix, pourcentage&#60;/span&#62;):&#60;/span&#62;\r\n    &#60;span class=\"hljs-keyword\"&#62;return&#60;/span&#62; prix * (&#60;span class=\"hljs-number\"&#62;1&#60;/span&#62; - pourcentage / &#60;span class=\"hljs-number\"&#62;100&#60;/span&#62;)\r\n&#60;/code&#62;&#60;/pre&#62;\r\n&#60;!----&#62;&#60;/div&#62;\r\n&#60;/div&#62;\r\n&#60;/div&#62;\r\n&#60;h3&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;/h3&#62;\r\n&#60;p&#62;&#60;strong&#62;II. Vous demandez à l\'IA :&#60;/strong&#62; &#60;code&#62;\"Génère des tests unitaires avec pytest pour la fonction calculer_remise.\"&#60;/code&#62;&#60;/p&#62;\r\n&#60;p&#62;&#60;strong&#62;III. L\'IA génère le fichier de test complet :&#60;/strong&#62;&#60;/p&#62;\r\n&#60;h3&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;/h3&#62;\r\n&#60;div class=\"code-block ng-tns-c3523328237-395 ng-animate-disabled ng-trigger ng-trigger-codeBlockRevealAnimation\" style=\"display: block;\" data-hveid=\"0\" data-ved=\"0CAAQhtANahgKEwiK7smt46iQAxUAAAAAHQAAAAAQrwY\"&#62;\r\n&#60;div class=\"code-block-decoration header-formatted gds-title-s ng-tns-c3523328237-395 ng-star-inserted\"&#62; &#60;/div&#62;\r\n&#60;!----&#62;\r\n&#60;div class=\"formatted-code-block-internal-container ng-tns-c3523328237-395\"&#62;\r\n&#60;div class=\"animated-opacity ng-tns-c3523328237-395\"&#62;\r\n&#60;pre class=\"ng-tns-c3523328237-395\"&#62;&#60;code class=\"code-container formatted ng-tns-c3523328237-395\" role=\"text\" data-test-id=\"code-content\"&#62;&#60;span class=\"hljs-keyword\"&#62;import&#60;/span&#62; pytest\r\n&#60;span class=\"hljs-keyword\"&#62;from&#60;/span&#62; remise &#60;span class=\"hljs-keyword\"&#62;import&#60;/span&#62; calculer_remise\r\n\r\n&#60;span class=\"hljs-function\"&#62;&#60;span class=\"hljs-keyword\"&#62;def&#60;/span&#62; &#60;span class=\"hljs-title\"&#62;test_remise_standard&#60;/span&#62;():&#60;/span&#62;\r\n    &#60;span class=\"hljs-keyword\"&#62;assert&#60;/span&#62; calculer_remise(&#60;span class=\"hljs-number\"&#62;100&#60;/span&#62;, &#60;span class=\"hljs-number\"&#62;20&#60;/span&#62;) == &#60;span class=\"hljs-number\"&#62;80.0&#60;/span&#62;\r\n\r\n&#60;span class=\"hljs-function\"&#62;&#60;span class=\"hljs-keyword\"&#62;def&#60;/span&#62; &#60;span class=\"hljs-title\"&#62;test_remise_zero&#60;/span&#62;():&#60;/span&#62;\r\n    &#60;span class=\"hljs-keyword\"&#62;assert&#60;/span&#62; calculer_remise(&#60;span class=\"hljs-number\"&#62;100&#60;/span&#62;, &#60;span class=\"hljs-number\"&#62;0&#60;/span&#62;) == &#60;span class=\"hljs-number\"&#62;100.0&#60;/span&#62;\r\n\r\n&#60;span class=\"hljs-function\"&#62;&#60;span class=\"hljs-keyword\"&#62;def&#60;/span&#62; &#60;span class=\"hljs-title\"&#62;test_remise_complete&#60;/span&#62;():&#60;/span&#62;\r\n    &#60;span class=\"hljs-keyword\"&#62;assert&#60;/span&#62; calculer_remise(&#60;span class=\"hljs-number\"&#62;100&#60;/span&#62;, &#60;span class=\"hljs-number\"&#62;100&#60;/span&#62;) == &#60;span class=\"hljs-number\"&#62;0.0&#60;/span&#62;\r\n&#60;/code&#62;&#60;/pre&#62;\r\n&#60;!----&#62;&#60;/div&#62;\r\n&#60;/div&#62;\r\n&#60;/div&#62;\r\n&#60;h3&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;!----&#62;&#60;/h3&#62;\r\n&#60;p&#62; &#60;/p&#62;\r\n&#60;h3&#62;&#60;strong&#62;4. Règles d\'Or : Bonnes Pratiques et Points de Vigilance Essentiels&#60;/strong&#62;&#60;/h3&#62;\r\n&#60;p&#62;Pour tirer le meilleur parti de l\'IA tout en évitant les pièges, suivez ces recommandations :&#60;/p&#62;\r\n&#60;ul&#62;\r\n&#60;li&#62;\r\n&#60;p&#62;&#60;strong&#62;✅ Soyez Précis dans vos Requêtes (Prompts) :&#60;/strong&#62; Donnez du contexte, définissez le format de sortie et spécifiez les contraintes.&#60;/p&#62;\r\n&#60;/li&#62;\r\n&#60;li&#62;\r\n&#60;p&#62;&#60;strong&#62;✅ Utilisez l\'IA comme un Levier, pas une Béquille :&#60;/strong&#62; L\'IA est un excellent point de départ, mais le développeur reste le pilote.&#60;/p&#62;\r\n&#60;/li&#62;\r\n&#60;li&#62;\r\n&#60;p&#62;&#60;strong&#62;⚠️ Vérifiez Toujours le Code Généré :&#60;/strong&#62; Auditez la sécurité, la performance et les \"hallucinations\" (fonctions qui n\'existent pas).&#60;/p&#62;\r\n&#60;/li&#62;\r\n&#60;li&#62;\r\n&#60;p&#62;&#60;strong&#62;⚠️ Protégez vos Données Sensibles :&#60;/strong&#62; Ne collez jamais d\'informations confidentielles (code propriétaire, données clients, clés d\'API) dans les interfaces publiques des IA.&#60;/p&#62;\r\n&#60;/li&#62;\r\n&#60;/ul&#62;',1,2,6,'2025-10-16 15:37:41','2025-10-16 15:37:41','2025-10-16 17:36:09',NULL);
