INSERT INTO `glpi_knowbaseitems_revisions` VALUES
(1,2,1,'Sécurité : Identifier et réagir face à une tentative de phishing Version : 1.0','&#60;p&#62;&#60;strong&#62;Table des Matières :&#60;/strong&#62;&#60;/p&#62;\r\n&#60;ol start=\"1\"&#62;\r\n&#60;li&#62;\r\n&#60;p&#62;Définition : Qu\'est-ce que le phishing ?&#60;/p&#62;\r\n&#60;/li&#62;\r\n&#60;li&#62;\r\n&#60;p&#62;Les 5 indices qui doivent vous alerter&#60;/p&#62;\r\n&#60;/li&#62;\r\n&#60;li&#62;\r\n&#60;p&#62;La procédure officielle à suivre&#60;/p&#62;\r\n&#60;/li&#62;\r\n&#60;li&#62;\r\n&#60;p&#62;J\'ai cliqué sur un lien, que faire ?&#60;/p&#62;\r\n&#60;/li&#62;\r\n&#60;/ol&#62;\r\n&#60;p&#62;&#60;strong&#62;Contenu :&#60;/strong&#62;&#60;/p&#62;\r\n&#60;ul&#62;\r\n&#60;li&#62;\r\n&#60;p&#62;&#60;strong&#62;(1. Définition)&#60;/strong&#62; Le phishing est une technique de fraude visant à vous tromper pour vous voler des informations (mots de passe, données bancaires) ou vous faire réaliser une action (un virement). Les fraudeurs se font passer pour une personne ou une entité de confiance.&#60;/p&#62;\r\n&#60;/li&#62;\r\n&#60;li&#62;\r\n&#60;p&#62;&#60;strong&#62;(2. Les 5 indices)&#60;/strong&#62;&#60;/p&#62;\r\n&#60;ul&#62;\r\n&#60;li&#62;\r\n&#60;p&#62;&#60;strong&#62;L\'expéditeur :&#60;/strong&#62; L\'adresse mail est légèrement différente de l\'officielle (&#60;code&#62;contact@open-showroom.com&#60;/code&#62; au lieu de &#60;code&#62;contact@openshowroom.com&#60;/code&#62;).&#60;/p&#62;\r\n&#60;/li&#62;\r\n&#60;li&#62;\r\n&#60;p&#62;&#60;strong&#62;Le ton :&#60;/strong&#62; Le message est pressant, inhabituel ou menaçant (\"urgent\", \"dernier rappel\", \"votre compte sera suspendu\").&#60;/p&#62;\r\n&#60;/li&#62;\r\n&#60;li&#62;\r\n&#60;p&#62;&#60;strong&#62;Les fautes :&#60;/strong&#62; Le message contient des fautes d\'orthographe ou de grammaire.&#60;/p&#62;\r\n&#60;/li&#62;\r\n&#60;li&#62;\r\n&#60;p&#62;&#60;strong&#62;Les liens :&#60;/strong&#62; En survolant un lien avec la souris (sans cliquer), l\'adresse qui s\'affiche est suspecte ou ne correspond pas.&#60;/p&#62;\r\n&#60;/li&#62;\r\n&#60;li&#62;\r\n&#60;p&#62;&#60;strong&#62;La demande :&#60;/strong&#62; On vous demande des informations confidentielles ou une action inhabituelle (changer des coordonnées bancaires, effectuer un virement imprévu).&#60;/p&#62;\r\n&#60;/li&#62;\r\n&#60;/ul&#62;\r\n&#60;/li&#62;\r\n&#60;li&#62;\r\n&#60;p&#62;&#60;strong&#62;(3. La procédure officielle à suivre)&#60;/strong&#62;&#60;/p&#62;\r\n&#60;ol start=\"1\"&#62;\r\n&#60;li&#62;\r\n&#60;p&#62;&#60;strong&#62;NE PAS CLIQUER&#60;/strong&#62;, ne pas répondre.&#60;/p&#62;\r\n&#60;/li&#62;\r\n&#60;li&#62;\r\n&#60;p&#62;&#60;strong&#62;SIGNALER&#60;/strong&#62; l\'e-mail en le transférant au support informatique.&#60;/p&#62;\r\n&#60;/li&#62;\r\n&#60;li&#62;\r\n&#60;p&#62;&#60;strong&#62;SUPPRIMER&#60;/strong&#62; définitivement l\'e-mail.&#60;/p&#62;\r\n&#60;/li&#62;\r\n&#60;/ol&#62;\r\n&#60;/li&#62;\r\n&#60;li&#62;\r\n&#60;p&#62;&#60;strong&#62;(4. J\'ai cliqué, que faire ?)&#60;/strong&#62;&#60;/p&#62;\r\n&#60;ol start=\"1\"&#62;\r\n&#60;li&#62;\r\n&#60;p&#62;&#60;strong&#62;Déconnecter immédiatement&#60;/strong&#62; l\'ordinateur du réseau (couper le Wi-Fi ou débrancher le câble Ethernet).&#60;/p&#62;\r\n&#60;/li&#62;\r\n&#60;li&#62;\r\n&#60;p&#62;&#60;strong&#62;Contacter d\'urgence le support informatique&#60;/strong&#62; par téléphone.&#60;/p&#62;\r\n&#60;/li&#62;\r\n&#60;/ol&#62;\r\n&#60;/li&#62;\r\n&#60;/ul&#62;','',2,'2025-10-16 14:35:21');
