INSERT INTO `glpi_tickets` VALUES
(1,0,'[Comptabilité] Demande de suppression du serveur Zefyr','2025-10-13 11:00:00',NULL,NULL,'2025-10-13 15:55:01','2025-10-16 13:48:52',2,4,4,2,'&#60;p&#62;Le chef du service comptabilité, Raphaël, demande la libération des ressources (serveur et BDD) allouées au logiciel Zefyr. Il a déjà supprimé les accès pour son équipe, arguant d\'une maîtrise insuffisante de l\'outil.&#60;/p&#62;',3,4,4,9,2,1,0,0,0,NULL,NULL,'2025-10-13 16:13:16',0,0,0,0,0,NULL,NULL,NULL,NULL,0,0,0,17701,0,0,0,0,'2025-10-13 14:30:36'),
(2,0,'[URGENT] Accès à l\'application Zefyr bloqué','2025-10-13 12:41:00',NULL,NULL,'2025-10-13 15:59:15','2025-10-16 13:49:12',2,4,4,3,'&#60;p&#62;Steeve du service comptabilité signale ne plus avoir accès au logiciel Zefyr. Cet accès est critique pour son travail quotidien, notamment pour les exports d\'écritures comptables. Il est bloqué et demande un rétablissement immédiat de ses droits. Il mentionne que la demande de suppression vient de son chef de service.&#60;/p&#62;',5,4,5,5,1,1,0,0,0,NULL,NULL,'2025-10-13 16:13:16',0,0,0,0,0,NULL,NULL,NULL,NULL,0,0,0,8295,0,0,0,0,'2025-10-13 14:32:42'),
(3,0,'[URGENT] Mail suspect de phishing demandant un virement','2025-10-13 13:40:00','2025-10-16 18:33:07','2025-10-16 14:40:02','2025-10-13 16:02:27','2025-10-16 18:33:07',2,6,4,3,'&#60;p&#62;Sophie a reçu un e-mail semblant provenir d\'un fournisseur habituel, mais contenant une demande de virement suspecte. L\'adresse de l\'expéditeur semble différente de celle habituellement utilisée.&#60;/p&#62;',4,4,4,17,1,1,0,0,0,NULL,NULL,'2025-10-16 14:40:02',0,0,0,0,0,NULL,NULL,NULL,NULL,253606,23181,9196,8547,0,0,0,0,'2025-10-13 14:35:05'),
(4,0,'[Projet] Configuration d\'un tunnel VPN IPSec avec le partenaire Ocito','2025-10-13 15:00:00',NULL,NULL,'2025-10-13 16:03:13','2025-10-22 07:34:17',2,4,4,4,'&#60;p&#62;L\'équipe commerciale a besoin d\'un accès sécurisé à un service web hébergé chez notre partenaire Ocito. Les machines du réseau local 10.0.1.0/24 doivent pouvoir atteindre cette ressource.&#60;/p&#62;',4,3,4,14,2,1,0,0,0,NULL,NULL,'2025-10-13 16:13:16',0,0,0,0,0,NULL,NULL,NULL,NULL,0,0,0,3793,0,0,0,0,'2025-10-13 14:37:27'),
(5,0,'[Comptabilité] Mot de passe invalide - Blocage de connexion','2025-10-13 13:30:00','2025-10-16 18:33:21','2025-10-16 14:54:02','2025-10-13 16:02:47','2025-10-16 18:33:21',2,6,4,3,'&#60;p&#62;L\'utilisateur Charly ne peut plus se connecter à sa session Windows, quel que soit le poste utilisé. Le message d\'erreur est \"Mot de passe invalide\". Un problème matériel (clavier) a été écarté.&#60;/p&#62;',3,3,3,4,1,1,0,0,0,NULL,NULL,'2025-10-16 14:54:02',0,0,0,0,0,NULL,NULL,NULL,NULL,254474,22927,9768,9167,0,0,0,0,'2025-10-13 14:38:44'),
(6,0,'[Développement] Demande de guide pour l\'utilisation de l\'IA','2025-10-13 17:45:00','2025-10-16 18:33:30','2025-10-16 15:47:02','2025-10-13 16:02:56','2025-10-16 18:33:30',2,6,4,1,'&#60;p&#62;René, de l\'équipe de développement, souhaite explorer l\'utilisation d\'outils d\'Intelligence Artificielle pour améliorer et accélérer son travail. Il demande des recommandations et un guide de bonnes pratiques.&#60;/p&#62;',1,3,2,7,2,1,0,0,0,NULL,NULL,'2025-10-16 15:47:02',0,0,0,0,0,NULL,NULL,NULL,NULL,257626,4484,0,1,0,0,0,0,'2025-10-13 14:39:47'),
(7,0,'Demande d’accès root pour débogage','2025-10-13 13:30:00',NULL,NULL,'2025-10-13 16:00:07','2025-10-16 18:30:15',2,2,4,3,'&#60;p&#62;Édouard, de l\'équipe de développement, sollicite un accès &#60;code&#62;root&#60;/code&#62; sur une machine pour déboguer un problème d\'affichage sur un navigateur. D\'après l\'analyse initiale, son besoin réel semble être un accès aux fichiers de logs de l\'application.&#60;/p&#62;',2,2,2,16,2,1,0,0,0,NULL,NULL,NULL,0,0,0,0,0,NULL,NULL,NULL,NULL,267419,0,0,9007,0,0,0,0,'2025-10-13 15:42:38'),
(8,0,'Réception de nouveaux téléphones','2025-10-13 13:45:00',NULL,NULL,'2025-10-13 16:00:21','2025-10-16 18:30:15',2,2,4,4,'&#60;p&#62;Philippe demande quand il recevra son nouveau téléphone professionnel.&#60;/p&#62;',1,1,1,12,2,1,0,0,0,NULL,NULL,NULL,0,0,0,0,0,NULL,NULL,NULL,NULL,267419,0,0,8121,0,0,0,0,'2025-10-13 15:43:33'),
(9,0,'Clim en panne - Code alerte E458','2025-10-13 15:30:00',NULL,NULL,'2025-10-13 16:00:53','2025-10-28 07:58:18',2,2,4,4,'&#60;p&#62;La climatisation n°3 de la salle serveur est en panne et affiche un code d\'erreur \"E458\".&#60;/p&#62;',5,1,2,2,1,1,0,0,0,NULL,NULL,NULL,0,0,0,0,0,NULL,NULL,NULL,NULL,267419,0,0,1853,0,0,0,0,'2025-10-13 15:45:18'),
(10,0,'PDG – Problème d\'installation iTunes','2025-10-13 16:45:00',NULL,NULL,'2025-10-13 16:01:17','2025-10-16 18:30:15',2,2,4,4,'&#60;p&#62;Guillaume, notre PDG, signale qu\'il ne parvient pas à installer le logiciel iTunes sur son ordinateur professionnel.&#60;/p&#62;',5,1,2,5,2,1,0,0,0,NULL,NULL,NULL,0,0,0,0,0,NULL,NULL,NULL,NULL,267419,0,0,1,0,0,0,0,'2025-10-13 15:46:12'),
(11,0,'[URGENT] Machine infectée','2025-10-13 17:30:00',NULL,NULL,'2025-10-13 16:03:32','2025-10-16 14:21:50',2,4,4,3,'&#60;p&#62;Le poste de travail de Samuel est devenu inutilisable (extrêmement lent, comportement anormal) juste après l\'ouverture d\'un devis reçu par e-mail qui semblait suspect.&#60;/p&#62;',5,5,5,18,1,1,0,0,0,NULL,NULL,'2025-10-16 14:21:50',0,0,0,0,0,NULL,NULL,NULL,NULL,252286,0,0,1,0,0,0,0,'2025-10-13 15:47:01'),
(12,0,'Demande de mise en place d\'un tunnel VPN IPSec - OpenShowroom / Ocito','2025-10-13 09:23:25',NULL,NULL,'2025-10-22 07:26:54','2025-10-22 07:31:26',2,2,2,1,'&#60;p&#62;&#60;strong&#62;Bonjour,&#60;/strong&#62;&#60;/p&#62;\n&#60;p&#62;Afin de permettre à notre équipe commerciale d\'accéder à votre service web, nous souhaiterions mettre en place un tunnel VPN IPSec Site-to-Site entre nos deux infrastructures.&#60;/p&#62;\n&#60;p&#62;Voici les informations de notre point de terminaison VPN (côté OpenShowroom) :&#60;/p&#62;\n&#60;ul&#62;\n&#60;li&#62;\n&#60;p&#62;&#60;strong&#62;IP Publique de notre pare-feu :&#60;/strong&#62; &#60;code&#62;195.210.77.33&#60;/code&#62;&#60;/p&#62;\n&#60;/li&#62;\n&#60;li&#62;\n&#60;p&#62;&#60;strong&#62;Réseaux locaux à autoriser (Phase 2) :&#60;/strong&#62; &#60;code&#62;10.0.1.0/24&#60;/code&#62;&#60;/p&#62;\n&#60;/li&#62;\n&#60;/ul&#62;\n&#60;p&#62;Pourriez-vous nous transmettre en retour les informations techniques de votre côté ?&#60;/p&#62;\n&#60;ul&#62;\n&#60;li&#62;\n&#60;p&#62;Votre IP Publique de point de terminaison VPN.&#60;/p&#62;\n&#60;/li&#62;\n&#60;li&#62;\n&#60;p&#62;Les sous-réseaux distants que nous devrons joindre.&#60;/p&#62;\n&#60;/li&#62;\n&#60;li&#62;\n&#60;p&#62;Les paramètres de chiffrement que vous préconisez pour la Phase 1 (IKE) et la Phase 2 (ESP).&#60;/p&#62;\n&#60;/li&#62;\n&#60;/ul&#62;\n&#60;p&#62;Nous restons à votre disposition pour planifier une session de test dès que la configuration sera prête de part et d\'autre.&#60;/p&#62;\n&#60;p&#62;&#60;strong&#62;Cordialement,&#60;/strong&#62;&#60;/p&#62;\n&#60;p&#62;&#60;strong&#62;L\'équipe de support informatique&#60;/strong&#62; &#60;strong&#62;OpenShowroom&#60;/strong&#62;&#60;/p&#62;',4,3,4,14,2,1,0,0,0,NULL,NULL,NULL,0,0,0,0,0,NULL,NULL,NULL,NULL,0,0,0,770609,0,1,0,0,'2025-10-22 07:26:54'),
(13,0,'Demande de mise en place d\'un tunnel VPN IPSec Site-to-Site avec un partenaire pour un besoin métier.','2025-10-13 09:33:51',NULL,NULL,'2025-10-22 07:34:17','2025-10-22 07:39:01',2,4,2,2,'&#60;p&#62;Demande d\'Élise (Équipe commerciale) pour configurer un tunnel VPN IPSec avec le partenaire Ocito. Le besoin est de permettre au réseau 10.0.1.0/24 d\'accéder à un service web chez ce partenaire.&#60;/p&#62;',4,3,4,14,2,1,0,0,0,NULL,NULL,'2025-10-22 07:39:01',0,0,0,0,0,NULL,NULL,NULL,NULL,0,0,0,770426,0,0,0,0,'2025-10-22 07:34:17');
